import React, { useState, useEffect } from 'react'
import { pondService, environmentLogService, sensorService } from '../../services/api'
import { buildAllThresholdAlerts } from '../../services/thresholdAlertService'
import { useAuth } from '../../context/AuthContext'
import DashboardCard, { evaluateMetric } from '../../components/DashboardCard'
import '../../styles/dashboard.css'
import '../../styles/dashboard-cards.css'
import '../../styles/technician/technician-layout.css'

export const TechnicianDashboard = () => {
  const { realtimeSensorData } = useAuth()
  const [monitoredPonds, setMonitoredPonds] = useState([])
  const [recentEnvironmentLogs, setRecentEnvironmentLogs] = useState([])
  const [activeSensors, setActiveSensors] = useState([])
  const [thresholdAlerts, setThresholdAlerts] = useState([])
  const [thresholdsMap, setThresholdsMap] = useState({})
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    try {
      setLoading(true)
      const [pondsRes] = await Promise.all([
        pondService.getAllPonds(),
      ])
      const ponds = pondsRes.data.data || []
      setMonitoredPonds(ponds)

      // Fetch thresholds for all ponds
      const thresholds = await Promise.all(
        ponds.map(async (pond) => {
          try {
            const response = await environmentLogService.getThresholdsByPond(pond.pond_id)
            return {
              pondId: pond.pond_id,
              thresholds: response?.data?.data || null,
            }
          } catch (err) {
            return { pondId: pond.pond_id, thresholds: null }
          }
        })
      )

      const thresholdsMapLocal = {}
      thresholds.forEach(({ pondId, thresholds: thresh }) => {
        if (thresh) {
          thresholdsMapLocal[String(pondId)] = thresh
        }
      })
      setThresholdsMap(thresholdsMapLocal)
    } catch (err) {
      setError('Lỗi tải dữ liệu')
      console.error(err)
    } finally {
      setLoading(false)
    }
  }

  // Compute threshold alerts when realtime data changes
  useEffect(() => {
    if (monitoredPonds.length > 0 && Object.keys(thresholdsMap).length > 0 && realtimeSensorData) {
      const alerts = buildAllThresholdAlerts(monitoredPonds, realtimeSensorData, thresholdsMap)
      setThresholdAlerts(alerts)
    }
  }, [realtimeSensorData, monitoredPonds, thresholdsMap])

  // Calculate monitoring statistics
  const monitoringStats = {
    totalPonds: monitoredPonds.length,
    activeSensors: monitoredPonds.reduce((acc, pond) => acc + (pond.sensors?.length || 0), 0),
    recentLogs: recentEnvironmentLogs.length,
  }

  if (loading) {
    return (
      <div className="dashboard">
        <div className="flex-center page-loading">
          <div className="spinner"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="dashboard technician-page-shell">
      <div className="dashboard-header">
        <h1>🔬 Kỹ thuật viên giám sát</h1>
        <p>Theo dõi môi trường & cảm biến trong ao</p>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      <section className="dashboard-cards-container">
        <DashboardCard
          title="Tổng số ao"
          value={monitoringStats.totalPonds}
          rating={evaluateMetric('ponds', monitoringStats.totalPonds)}
          description="Ao đang giám sát"
        />
        <DashboardCard
          title="Cảm biến hoạt động"
          value={monitoringStats.activeSensors}
          rating={evaluateMetric('sensors', monitoringStats.activeSensors)}
          description="Tổng số cảm biến"
        />
      </section>

      {/* Quick Actions */}
      <div className="quick-actions">
        <h2>🚀 Hành động nhanh</h2>
        <div className="actions-grid">
          <a href="/technician/environment" className="action-btn">
            <span className="action-icon">🌡️</span>
            <span className="action-label">Nhập môi trường</span>
          </a>
          <a href="/technician/sensor" className="action-btn">
            <span className="action-icon">📡</span>
            <span className="action-label">Cảm biến realtime</span>
          </a>
        </div>
      </div>

      {/* Monitored Ponds */}
      <div className="recent-section">
        <h2>🏞️ Ao đang giám sát</h2>
        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                <th>Mã ao</th>
                <th>Tên ao</th>
                <th>Diện tích</th>
                <th>Trạng thái</th>
                <th>Hành động</th>
              </tr>
            </thead>
            <tbody>
              {monitoredPonds.length > 0 ? (
                monitoredPonds.map((pond) => (
                  <tr key={pond.pond_id}>
                    <td><strong>{pond.pond_code}</strong></td>
                    <td>{pond.pond_name}</td>
                    <td>{pond.area_m2} m²</td>
                    <td>
                      <span className="status-badge status-active">
                        {pond.status}
                      </span>
                    </td>
                    <td>
                      <a href={`/technician/environment`} className="btn btn-sm btn-primary">
                        🌡️ Giám sát
                      </a>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="5" className="table-empty-cell">
                    Bạn chưa được phân công ao nào
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Features */}
      <div className="recent-section section-stack">
        <h2>📌 Tính năng chính</h2>
        <div className="info-boxes">
          <div className="info-box">
            <h3>✨ Quyền hạn</h3>
            <ul>
